/**
 * mechsense-api サーバー統合テスト
 * 使い方: npm test  (server.js を自動起動・テスト後停止)
 */

'use strict';

const http = require('http');

const BASE = 'http://localhost:3000/api/v1';
let pass = 0, fail = 0;

// ─── ヘルパー ────────────────────────────────────────────

function post(path, body) {
  return new Promise((resolve, reject) => {
    const data = JSON.stringify(body);
    const req = http.request(`${BASE}${path}`, {
      method: 'POST',
      headers: { 'Content-Type': 'application/json', 'Content-Length': Buffer.byteLength(data) },
    }, res => {
      let buf = '';
      res.on('data', c => buf += c);
      res.on('end', () => resolve({ status: res.statusCode, body: JSON.parse(buf) }));
    });
    req.on('error', reject);
    req.write(data);
    req.end();
  });
}

function get(path) {
  return new Promise((resolve, reject) => {
    http.get(`${BASE}${path}`, res => {
      let buf = '';
      res.on('data', c => buf += c);
      res.on('end', () => resolve({ status: res.statusCode, body: JSON.parse(buf) }));
    }).on('error', reject);
  });
}

function assert(label, cond) {
  if (cond) { console.log(`  ✅ ${label}`); pass++; }
  else       { console.log(`  ❌ ${label}`); fail++; }
}

// ─── テストケース ─────────────────────────────────────────

async function run() {
  console.log('=== mechsense-api 統合テスト ===\n');

  // ヘルスチェック
  console.log('--- GET /health ---');
  const h = await get('/health');
  assert('status 200', h.status === 200);
  assert('ok=true', h.body.ok === true);
  assert('version 1.2.0', h.body.version === '1.2.0');

  // 材料一覧
  console.log('\n--- GET /materials/spring ---');
  const mat = await get('/materials/spring');
  assert('ok=true', mat.body.ok === true);
  assert('6材料', mat.body.materials.length === 6);
  assert('SW-B 含む', mat.body.materials.some(m => m.key === 'SW-B'));

  // ばね計算（正常）
  console.log('\n--- POST /spring/calc (SW-B d=2 D=15 Na=5 P=50) ---');
  const sp = await post('/spring/calc', { d: 2, D: 15, Na: 5, P: 50, mat: 'SW-B' });
  assert('status 200', sp.status === 200);
  assert('ok=true', sp.body.result.judgment.status === 'OK');
  assert('tau≈285.85', Math.abs(sp.body.result.mechanics.tau - 285.85) < 0.1);
  assert('ratio≈0.1945', Math.abs(sp.body.result.mechanics.ratio - 0.1945) < 0.001);
  assert('k≈9.304', Math.abs(sp.body.result.mechanics.k - 9.304) < 0.01);

  // ばね計算（応力超過）
  console.log('\n--- POST /spring/calc (応力超過ケース) ---');
  const spNG = await post('/spring/calc', { d: 1, D: 15, Na: 5, P: 200, mat: 'SW-B' });
  assert('status 200', spNG.status === 200);
  assert('NG_STRESS 検出', spNG.body.result.judgment.status === 'NG_STRESS');
  assert('isSafe=false', spNG.body.result.judgment.isSafe === false);

  // ばね計算（バリデーションエラー）
  console.log('\n--- POST /spring/calc (必須欠如) ---');
  const spErr = await post('/spring/calc', { d: 2 });
  assert('status 400', spErr.status === 400);
  assert('ok=false', spErr.body.ok === false);
  assert('error メッセージあり', typeof spErr.body.error === 'string');

  // ボルト計算（正常）
  console.log('\n--- POST /bolt/calc (M10 10.9 steel dry) ---');
  const bo = await post('/bolt/calc', { d: 10, grade: '10.9', partMat: 'steel', mu: 'dry' });
  assert('status 200', bo.status === 200);
  assert('ok=true', bo.body.ok === true);
  assert('T_lim≈94.31', Math.abs(bo.body.result.torque.T_lim - 94.31) < 0.1);
  assert('K≈0.2032', Math.abs(bo.body.result.torque.K - 0.2032) < 0.001);

  // ボルト計算（軟質材制限）
  console.log('\n--- POST /bolt/calc (M8 8.8 aluminum lube) ---');
  const boAl = await post('/bolt/calc', { d: 8, grade: '8.8', partMat: 'aluminum', mu: 'lube' });
  assert('status 200', boAl.status === 200);
  // 注: 鋼の場合は isMaterialLimit=false が正常。アルミのログは結果確認のみ
  assert('ok=true', boAl.body.ok === true);

  // 共振計算（SAFE）
  console.log('\n--- POST /resonance/calc (SW-B d=2 D=15 Na=5 rpm=3000) ---');
  const re = await post('/resonance/calc', { d: 2, D: 15, Na: 5, mat: 'SW-B', rpm: 3000 });
  assert('status 200', re.status === 200);
  assert('fn_surge≈894.7', Math.abs(re.body.result.resonance.fn_surge - 894.7) < 1);
  assert('SAFE 判定', re.body.result.judgment.status === 'SAFE');
  assert('4次固有振動数', re.body.result.resonance.fn_modes.length === 4);

  // combined エンドポイント
  console.log('\n--- POST /combined/spring-resonance ---');
  const co = await post('/combined/spring-resonance', { d: 2, D: 15, Na: 5, P: 50, mat: 'SW-B', rpm: 3000 });
  assert('status 200', co.status === 200);
  assert('spring.OK', co.body.spring.judgment.status === 'OK');
  assert('resonance.SAFE', co.body.resonance.judgment.status === 'SAFE');
  assert('module=Combined', co.body.module === 'Combined');

  // 404
  console.log('\n--- 404 ハンドリング ---');
  const nf = await get('/nonexistent');
  assert('status 404', nf.status === 404);
  assert('ok=false', nf.body.ok === false);

  // 結果
  console.log(`\n${'='.repeat(40)}`);
  console.log(`結果: ${pass} PASS / ${fail} FAIL`);
  if (fail > 0) process.exit(1);
}

// サーバー起動待ち後にテスト実行
setTimeout(run, 500).unref();
// server.js を require してポート 3000 でリッスン開始
require('./server.js');

